using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketBookingService
{
    private readonly EventBookingContext _context;

    public TicketBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        // Check if the event exists and has available seats
        var eventExists = await _context.Events.AnyAsync(e => e.EventId == eventId);
        if (!eventExists)
        {
            throw new ArgumentException("Invalid event ID");
        }

        var availableSeats = await _context.Events.FirstOrDefaultAsync(e => e.EventId == eventId).AvailableSeats;
        if (availableSeats < quantity)
        {
            throw new InvalidOperationException("Insufficient seats available");
        }

        // Update inventory and return true if successful
        var updatedInventory = await _context.Events.FirstOrDefaultAsync(e => e.EventId == eventId).UpdateInventoryAsync(quantity);
        if (updatedInventory)
        {
            return true;
        }

        // Return false if inventory update failed
        return false;
    }
}